type QuoteStep = { op: "quote"; items: Array<{ type: string }> };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

export const processScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => {
    let policyBase = 0;
    let firstInsurance = 0;
    for (const item of step.items) {
      if (item.type === "sword") {
        policyBase += 100;
        firstInsurance += 10;
      }
    }
    return { premium: policyBase + firstInsurance + 5 };
  });
  return { results };
};

