type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const itemBasePremium = (item: Item): number => {
  if (item.type === "sword") return 100;
  return 0;
};

const computeQuote = (items: Item[]): { premium: number } => {
  let policyBase = 0;
  let firstInsurance = 0;
  for (const item of items) {
    const base = itemBasePremium(item);
    policyBase += base;
    firstInsurance += base * 0.1;
  }
  return { premium: policyBase + firstInsurance + 5 };
};

export const processScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => computeQuote(step.items));
  return { results };
};

