type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

const MAIN_ITEM_BASE: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_BASE = 25;
const COMPONENT_BLOCK_BASE = 60;
const COMPONENT_BLOCK_SIZE = 3;

const componentsBase = (items: Item[]): number => {
  const count = items.filter((i) => COMPONENT_TYPES.has(i.type)).length;
  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE;
  return count * COMPONENT_BASE;
};

const mainItemsBase = (items: Item[]): number =>
  items
    .filter((i) => !COMPONENT_TYPES.has(i.type))
    .reduce((sum, i) => sum + (MAIN_ITEM_BASE[i.type] ?? 0), 0);

const computeQuote = (items: Item[]): { premium: number } => {
  const policyBase = mainItemsBase(items) + componentsBase(items);
  const firstInsurance = policyBase * 0.1;
  return { premium: policyBase + firstInsurance + 5 };
};

export const processScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => computeQuote(step.items));
  return { results };
};

