import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premium and processing fee
  it("empty item list yields premium 5 G (only processing fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("single sword for a newcomer yields base premium 100 G + first insurance 10 G + fee 5 G = 115 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("multiple items sum base premiums (sword + amulet, newcomer) = 100 + 60 + 16 first-ins + 5 fee = 181 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: false },
            { type: "amulet", material: "silver", enchantment: 2, cursed: false },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 181 }] });
  });

  // Component pricing
  it("two runes cost 50 G base premium (newcomer: + 5 first-ins + 5 fee = 60 G)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("three runes form a block at 60 G base premium (newcomer: + 6 first-ins + 5 fee = 71 G)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("four runes cost 100 G base premium (block requires exactly 3; newcomer = 100 + 10 + 5 = 115 G)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("three runes + three moonstones form two separate blocks = 120 G base premium", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    // 120 base + 12 first-ins + 5 fee = 137
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Item-specific modifiers
  it("cursed sword for a newcomer: 100 + 50 curse + 10 first-ins + 5 fee = 165 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it.todo("highly enchanted sword (enchantment 5) for a newcomer: 100 + 30 + 10 + 5 = 145 G");
  it.todo("cursed + highly-enchanted sword stacks both surcharges");

  // Policy-wide modifiers
  it.todo("long-standing customer (2 years) gets 20% loyalty discount on policy base premium");
  it.todo("second quote in a scenario gets 15% follow-up discount");

  // Cursed surcharge scope: only the cursed item
  it.todo("policy with cursed sword + plain amulet: curse surcharge applies only to cursed item's base premium");

  // Rounding
  it.todo("premium that yields 197.5 G rounds up to 198 G (in MHPCO's favor)");

  // Claim: basic reimbursement
  it.todo("regular sword damage 500 G yields payout 400 G (full minus 100 G deductible)");
  it.todo("rune damage 200 G yields payout 100 G (full minus 100 G deductible)");

  // Claim: multi-damage deductible
  it.todo("two damaged items in one incident apply the deductible once per item");

  // Claim: high enchantment vs dragon material
  it.todo("dragon-material sword enchantment 8 with damage 1000 G yields payout 400 G (50% then deductible)");
  it.todo("dragon-material sword enchantment 5 with damage 800 G yields payout 700 G (full then deductible)");
  it.todo("steel sword enchantment 9 with damage 1000 G yields payout 400 G (50% then deductible)");

  // Cap
  it.todo("two successive 1500 G claims on a sword (cap 2000): first 1400, then 600 remaining cap 0");

  // Payout rounding
  it.todo("payout that yields 350.5 G rounds down to 350 G (in MHPCO's favor)");

  // Errors
  it.todo("quote with unknown item type causes the scenario to fail");
  it.todo("claim referencing damage to an item not in the policy causes failure");
  it.todo("claim with negative damage amount causes failure");
  it.todo("claim with more damages of a type than insured causes failure");
});

