    customer.yearsWithMHPCO >= LOYALTY_YEARS ? policyBase * LOYALTY_DISCOUNT : 0;
  const followUpDiscount = quoteIndex > 0 ? policyBase * FOLLOWUP_DISCOUNT : 0;
  const premium =
